@js:
sort=[];
push=(title,url)=>sort.push({
	title:title,
	url:url,
	style:{
		layout_flexGrow:1,
		layout_flexBasisPercent:0.4
	}
});
const config={
	cate:{
		path:"/queryBooksByCateId",
		param:"cateId"
	},
	list:{
		path:"/queryBooksByListNo",
		param:"listNo"
	}
};
const categories=[
	{type:"cate",title:"现当代文学",id:1},
	{type:"cate",title:"散文随笔",id:2},
	{type:"cate",title:"外国文学",id:3},
	{type:"cate",title:"短篇小说",id:4},
	{type:"cate",title:"古代文学",id:5},
	{type:"cate",title:"其他",id:6},
	{type:"cate",title:"诗歌",id:9},
	{type:"list",title:"可阅日刊",id:3267},
	{type:"list",title:"20世纪中文小说百强",id:9393}
];
categories.forEach(item=>{
	const {path,param}=config[item.type];
	push(item.title,`${path}?page={{page}}&${param}=${item.id}`);
});
JSON.stringify(sort)

